import { LucideIcon } from "lucide-react";

interface MetricCardProps {
  title: string;
  value: string;
  change: string;
  changeType: "positive" | "negative" | "neutral";
  icon: LucideIcon;
}

const MetricCard = ({ title, value, change, changeType, icon: Icon }: MetricCardProps) => {
  const changeColor = changeType === "positive" 
    ? "text-success" 
    : changeType === "negative" 
    ? "text-destructive" 
    : "text-muted-foreground";

  return (
    <div className="rounded-xl border border-border bg-card p-6 transition-all hover:glow-primary hover:border-primary/30">
      <div className="flex items-center justify-between">
        <span className="text-sm text-muted-foreground">{title}</span>
        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
          <Icon className="h-5 w-5 text-primary" />
        </div>
      </div>
      <div className="mt-3">
        <p className="text-3xl font-bold text-foreground">{value}</p>
        <p className={`mt-1 text-sm ${changeColor}`}>{change}</p>
      </div>
    </div>
  );
};

export default MetricCard;

import { NavLink as RouterNavLink, NavLinkProps } from "react-router-dom";
import { forwardRef } from "react";
import { cn } from "@/lib/utils";

interface NavLinkCompatProps extends Omit<NavLinkProps, "className"> {
  className?: string;
  activeClassName?: string;
  pendingClassName?: string;
}

const NavLink = forwardRef<HTMLAnchorElement, NavLinkCompatProps>(
  ({ className, activeClassName, pendingClassName, to, ...props }, ref) => {
    return (
      <RouterNavLink
        ref={ref}
        to={to}
        className={({ isActive, isPending }) =>
          cn(className, isActive && activeClassName, isPending && pendingClassName)
        }
        {...props}
      />
    );
  },
);

NavLink.displayName = "NavLink";

export { NavLink };

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from '@/components/ui/popover';
import {
    Bell,
    Check,
    AlertTriangle,
    TrendingDown,
    DollarSign,
    Image,
    Loader2,
    Trash2,
    CheckCheck
} from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface Notification {
    id: string;
    type: string;
    title: string;
    message: string;
    read: boolean;
    created_at: string;
    metadata?: any;
}

export default function NotificationsPanel() {
    const { user } = useAuth();
    const queryClient = useQueryClient();
    const companyId = user?.company?.id;
    const [isOpen, setIsOpen] = useState(false);

    const { data: notifications = [], isLoading } = useQuery({
        queryKey: ['notifications', companyId],
        queryFn: async () => {
            if (!companyId) return [];
            const { data, error } = await supabase
                .from('notifications')
                .select('*')
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(20);
            if (error) throw error;
            return data as Notification[];
        },
        enabled: !!companyId && isOpen,
        refetchInterval: isOpen ? 30000 : false,
    });

    const unreadCount = notifications.filter(n => !n.read).length;

    const markAsRead = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await supabase
                .from('notifications')
                .update({ read: true })
                .eq('id', id);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['notifications', companyId] });
        },
    });

    const markAllAsRead = useMutation({
        mutationFn: async () => {
            if (!companyId) return;
            const { error } = await supabase
                .from('notifications')
                .update({ read: true })
                .eq('company_id', companyId)
                .eq('read', false);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['notifications', companyId] });
        },
    });

    const getIcon = (type: string) => {
        switch (type) {
            case 'creative_fatigue':
                return <TrendingDown className="w-4 h-4 text-yellow-500" />;
            case 'spend_alert':
                return <DollarSign className="w-4 h-4 text-red-500" />;
            case 'audit_issue':
                return <AlertTriangle className="w-4 h-4 text-orange-500" />;
            default:
                return <Bell className="w-4 h-4 text-ch-text-muted" />;
        }
    };

    return (
        <Popover open={isOpen} onOpenChange={setIsOpen}>
            <PopoverTrigger asChild>
                <Button variant="ghost" size="icon" className="relative">
                    <Bell className="w-5 h-5 text-ch-text-muted" />
                    {unreadCount > 0 && (
                        <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full w-5 h-5 flex items-center justify-center">
                            {unreadCount > 9 ? '9+' : unreadCount}
                        </span>
                    )}
                </Button>
            </PopoverTrigger>
            <PopoverContent className="w-80 p-0 bg-ch-gray border-ch-dark-gray" align="end">
                <div className="flex items-center justify-between p-3 border-b border-ch-dark-gray">
                    <h3 className="font-semibold text-ch-white">Notificações</h3>
                    {notifications.some(n => !n.read) && (
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => markAllAsRead.mutate()}
                            className="text-xs text-ch-text-muted hover:text-ch-white"
                        >
                            <CheckCheck className="w-4 h-4 mr-1" />
                            Marcar todas como lidas
                        </Button>
                    )}
                </div>

                <div className="max-h-80 overflow-y-auto">
                    {isLoading ? (
                        <div className="flex items-center justify-center py-8">
                            <Loader2 className="w-5 h-5 animate-spin text-ch-orange" />
                        </div>
                    ) : notifications.length > 0 ? (
                        notifications.map((notification) => (
                            <div
                                key={notification.id}
                                className={`p-3 border-b border-ch-dark-gray hover:bg-ch-dark-gray/50 cursor-pointer transition-colors ${!notification.read ? 'bg-ch-dark-gray/30' : ''
                                    }`}
                                onClick={() => !notification.read && markAsRead.mutate(notification.id)}
                            >
                                <div className="flex gap-3">
                                    <div className="flex-shrink-0 mt-0.5">
                                        {getIcon(notification.type)}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className={`text-sm font-medium ${notification.read ? 'text-ch-text-muted' : 'text-ch-white'}`}>
                                            {notification.title}
                                        </p>
                                        <p className="text-xs text-ch-text-dimmed line-clamp-2">
                                            {notification.message}
                                        </p>
                                        <p className="text-xs text-ch-text-dimmed mt-1">
                                            {formatDistanceToNow(new Date(notification.created_at), {
                                                addSuffix: true,
                                                locale: ptBR,
                                            })}
                                        </p>
                                    </div>
                                    {!notification.read && (
                                        <div className="w-2 h-2 rounded-full bg-ch-orange flex-shrink-0 mt-1.5" />
                                    )}
                                </div>
                            </div>
                        ))
                    ) : (
                        <div className="text-center py-8">
                            <Bell className="w-8 h-8 text-ch-text-dimmed mx-auto mb-2" />
                            <p className="text-sm text-ch-text-muted">Nenhuma notificação</p>
                        </div>
                    )}
                </div>
            </PopoverContent>
        </Popover>
    );
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import {
    TrendingUp,
    TrendingDown,
    Minus,
    Target,
    DollarSign,
    MousePointer,
    Eye,
    BarChart3,
    Loader2
} from 'lucide-react';

interface Benchmark {
    metric: string;
    label: string;
    value: number;
    benchmark: number;
    unit: string;
    isPercentage?: boolean;
    higherIsBetter?: boolean;
}

const INDUSTRY_BENCHMARKS = {
    ctr: 0.9, // 0.9% average CTR for Facebook ads
    cpc: 1.72, // $1.72 average CPC
    cpm: 11.54, // $11.54 average CPM
    conversion_rate: 9.21, // 9.21% average conversion rate
};

export default function PerformanceBenchmarks() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    const { data: metrics, isLoading } = useQuery({
        queryKey: ['performance-benchmarks', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('campaign_metrics')
                .select('impressions, clicks, spend, conversions')
                .eq('company_id', companyId);

            if (error) throw error;

            // Aggregate metrics
            const totals = (data || []).reduce(
                (acc, m) => ({
                    impressions: acc.impressions + (m.impressions || 0),
                    clicks: acc.clicks + (m.clicks || 0),
                    spend: acc.spend + (Number(m.spend) || 0),
                    conversions: acc.conversions + (m.conversions || 0),
                }),
                { impressions: 0, clicks: 0, spend: 0, conversions: 0 }
            );

            return {
                ctr: totals.impressions > 0 ? (totals.clicks / totals.impressions) * 100 : 0,
                cpc: totals.clicks > 0 ? totals.spend / totals.clicks : 0,
                cpm: totals.impressions > 0 ? (totals.spend / totals.impressions) * 1000 : 0,
                conversion_rate: totals.clicks > 0 ? (totals.conversions / totals.clicks) * 100 : 0,
            };
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000,
    });

    const benchmarks: Benchmark[] = [
        {
            metric: 'ctr',
            label: 'CTR',
            value: metrics?.ctr || 0,
            benchmark: INDUSTRY_BENCHMARKS.ctr,
            unit: '%',
            isPercentage: true,
            higherIsBetter: true,
        },
        {
            metric: 'cpc',
            label: 'CPC',
            value: metrics?.cpc || 0,
            benchmark: INDUSTRY_BENCHMARKS.cpc,
            unit: 'R$',
            higherIsBetter: false,
        },
        {
            metric: 'cpm',
            label: 'CPM',
            value: metrics?.cpm || 0,
            benchmark: INDUSTRY_BENCHMARKS.cpm,
            unit: 'R$',
            higherIsBetter: false,
        },
        {
            metric: 'conversion_rate',
            label: 'Taxa de Conversão',
            value: metrics?.conversion_rate || 0,
            benchmark: INDUSTRY_BENCHMARKS.conversion_rate,
            unit: '%',
            isPercentage: true,
            higherIsBetter: true,
        },
    ];

    const getPerformanceStatus = (benchmark: Benchmark) => {
        if (benchmark.value === 0) return { status: 'neutral', color: 'text-ch-text-muted', icon: Minus };

        const percentDiff = ((benchmark.value - benchmark.benchmark) / benchmark.benchmark) * 100;
        const isGood = benchmark.higherIsBetter ? percentDiff > 0 : percentDiff < 0;

        if (Math.abs(percentDiff) < 10) {
            return { status: 'neutral', color: 'text-yellow-500', icon: Minus };
        }

        if (isGood) {
            return { status: 'good', color: 'text-green-500', icon: TrendingUp };
        }

        return { status: 'bad', color: 'text-red-500', icon: TrendingDown };
    };

    const formatValue = (benchmark: Benchmark) => {
        if (benchmark.isPercentage) {
            return `${benchmark.value.toFixed(2)}%`;
        }
        return `R$ ${benchmark.value.toFixed(2)}`;
    };

    const getIcon = (metric: string) => {
        switch (metric) {
            case 'ctr':
                return MousePointer;
            case 'cpc':
                return DollarSign;
            case 'cpm':
                return Eye;
            case 'conversion_rate':
                return Target;
            default:
                return BarChart3;
        }
    };

    if (isLoading) {
        return (
            <div className="glass rounded-xl p-6 flex items-center justify-center">
                <Loader2 className="w-6 h-6 animate-spin text-ch-orange" />
            </div>
        );
    }

    return (
        <div className="glass rounded-xl p-6 space-y-4">
            <div className="flex items-center justify-between">
                <h3 className="font-semibold text-ch-white flex items-center gap-2">
                    <BarChart3 className="w-5 h-5 text-ch-orange" />
                    Benchmarks de Performance
                </h3>
                <span className="text-xs text-ch-text-dimmed">vs. média do mercado</span>
            </div>

            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                {benchmarks.map((benchmark) => {
                    const status = getPerformanceStatus(benchmark);
                    const Icon = getIcon(benchmark.metric);
                    const StatusIcon = status.icon;

                    return (
                        <div key={benchmark.metric} className="bg-ch-dark-gray rounded-lg p-4 space-y-2">
                            <div className="flex items-center justify-between">
                                <Icon className="w-4 h-4 text-ch-text-muted" />
                                <StatusIcon className={`w-4 h-4 ${status.color}`} />
                            </div>
                            <p className="text-2xl font-bold text-ch-white">
                                {formatValue(benchmark)}
                            </p>
                            <div className="flex items-center justify-between">
                                <p className="text-xs text-ch-text-dimmed">{benchmark.label}</p>
                                <p className="text-xs text-ch-text-dimmed">
                                    Benchmark: {benchmark.isPercentage ? `${benchmark.benchmark}%` : `R$ ${benchmark.benchmark.toFixed(2)}`}
                                </p>
                            </div>
                            <div className="w-full bg-ch-gray rounded-full h-1.5">
                                <div
                                    className={`h-1.5 rounded-full ${status.status === 'good'
                                            ? 'bg-green-500'
                                            : status.status === 'bad'
                                                ? 'bg-red-500'
                                                : 'bg-yellow-500'
                                        }`}
                                    style={{
                                        width: `${Math.min(100, Math.max(10, (benchmark.value / benchmark.benchmark) * 50))}%`,
                                    }}
                                />
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}

import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";

interface PerformanceChartProps {
  chartView: 'metrics' | 'costs';
}

const metricsData = [
  { name: "Seg", impressoes: 12400, cliques: 890, conversas: 48 },
  { name: "Ter", impressoes: 15200, cliques: 1120, conversas: 62 },
  { name: "Qua", impressoes: 13800, cliques: 980, conversas: 55 },
  { name: "Qui", impressoes: 18600, cliques: 1340, conversas: 78 },
  { name: "Sex", impressoes: 21200, cliques: 1580, conversas: 91 },
  { name: "Sáb", impressoes: 16800, cliques: 1200, conversas: 67 },
  { name: "Dom", impressoes: 14200, cliques: 1050, conversas: 58 },
];

const costsData = [
  { name: "Seg", cpm: 12.50, cpc: 1.40, cpl: 25.80 },
  { name: "Ter", cpm: 11.20, cpc: 1.35, cpl: 24.20 },
  { name: "Qua", cpm: 13.80, cpc: 1.41, cpl: 25.10 },
  { name: "Qui", cpm: 10.90, cpc: 1.38, cpl: 23.85 },
  { name: "Sex", cpm: 9.80, cpc: 1.26, cpl: 20.40 },
  { name: "Sáb", cpm: 11.50, cpc: 1.40, cpl: 25.00 },
  { name: "Dom", cpm: 12.20, cpc: 1.52, cpl: 24.50 },
];

const CustomTooltip = ({ active, payload, label, chartView }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="glass rounded-lg p-3 border border-white/10">
        <p className="text-sm font-medium text-ch-white mb-2">{label}</p>
        {payload.map((entry: any, index: number) => (
          <p key={index} className="text-xs" style={{ color: entry.color }}>
            {entry.name}: {chartView === 'costs' ? `R$ ${entry.value.toFixed(2)}` : entry.value.toLocaleString()}
          </p>
        ))}
      </div>
    );
  }
  return null;
};

const PerformanceChart = ({ chartView }: PerformanceChartProps) => {
  const data = chartView === 'metrics' ? metricsData : costsData;
  const isMetrics = chartView === 'metrics';

  return (
    <div className="h-full w-full">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={data}>
          <defs>
            {isMetrics ? (
              <>
                <linearGradient id="colorImpressoes" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#00d4ff" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#00d4ff" stopOpacity={0} />
                </linearGradient>
                <linearGradient id="colorCliques" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#a78bfa" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#a78bfa" stopOpacity={0} />
                </linearGradient>
                <linearGradient id="colorConversas" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#fbbf24" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#fbbf24" stopOpacity={0} />
                </linearGradient>
              </>
            ) : (
              <>
                <linearGradient id="colorCPM" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#00d4ff" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#00d4ff" stopOpacity={0} />
                </linearGradient>
                <linearGradient id="colorCPC" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#a78bfa" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#a78bfa" stopOpacity={0} />
                </linearGradient>
                <linearGradient id="colorCPL" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#fbbf24" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#fbbf24" stopOpacity={0} />
                </linearGradient>
              </>
            )}
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" />
          <XAxis
            dataKey="name"
            stroke="rgba(255,255,255,0.3)"
            fontSize={11}
            fontWeight="bold"
            tick={{ fill: 'rgba(255,255,255,0.5)' }}
          />
          <YAxis
            stroke="rgba(255,255,255,0.3)"
            fontSize={11}
            fontWeight="bold"
            tick={{ fill: 'rgba(255,255,255,0.5)' }}
          />
          <Tooltip content={<CustomTooltip chartView={chartView} />} />
          {isMetrics ? (
            <>
              <Area
                type="monotone"
                dataKey="impressoes"
                name="Impressões"
                stroke="#00d4ff"
                fillOpacity={1}
                fill="url(#colorImpressoes)"
                strokeWidth={2.5}
              />
              <Area
                type="monotone"
                dataKey="cliques"
                name="Cliques"
                stroke="#a78bfa"
                fillOpacity={1}
                fill="url(#colorCliques)"
                strokeWidth={2.5}
              />
              <Area
                type="monotone"
                dataKey="conversas"
                name="Conversas"
                stroke="#fbbf24"
                fillOpacity={1}
                fill="url(#colorConversas)"
                strokeWidth={2.5}
              />
            </>
          ) : (
            <>
              <Area
                type="monotone"
                dataKey="cpm"
                name="CPM"
                stroke="#00d4ff"
                fillOpacity={1}
                fill="url(#colorCPM)"
                strokeWidth={2.5}
              />
              <Area
                type="monotone"
                dataKey="cpc"
                name="CPC"
                stroke="#a78bfa"
                fillOpacity={1}
                fill="url(#colorCPC)"
                strokeWidth={2.5}
              />
              <Area
                type="monotone"
                dataKey="cpl"
                name="CPL"
                stroke="#fbbf24"
                fillOpacity={1}
                fill="url(#colorCPL)"
                strokeWidth={2.5}
              />
            </>
          )}
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export default PerformanceChart;
